#!/bin/bash
# LyAi — instalador completo para servidor dedicado Hetzner
# Uso: sudo bash lyai-install.sh
set -euo pipefail

LYAI_DIR="/var/www/lyai"
CERT_DIR="/etc/letsencrypt/live/lyai.ch"

echo ""; echo "▶  [1/7] Dependencias del sistema"; echo ""
export DEBIAN_FRONTEND=noninteractive
apt-get update -q
apt-get install -y python3 python3-venv python3-pip nginx curl build-essential

echo ""; echo "▶  [2/7] Node.js 22 LTS"; echo ""
if ! command -v node &>/dev/null; then
  curl -fsSL https://deb.nodesource.com/setup_22.x | bash -
  apt-get install -y nodejs
fi
node --version; npm --version

echo ""; echo "▶  [3/7] Creando estructura de directorios"; echo ""
mkdir -p "$LYAI_DIR/backend"
mkdir -p "$LYAI_DIR/frontend"

echo ""; echo "▶  [4/7] Extrayendo código fuente"; echo ""

# ── backend/main.py ────────────────────────────────────────────────────────
echo "" | base64 -d > "$LYAI_DIR/backend/main.py"

# ── backend/requirements.txt ──────────────────────────────────────────────
echo "ZmFzdGFwaT09MC4xMTUuMAp1dmljb3JuW3N0YW5kYXJkXT09MC4zMi4wCnB5ZGFudGljPT0yLjkuMgo=" | base64 -d > "$LYAI_DIR/backend/requirements.txt"

# ── frontend source (tar.gz base64) ──────────────────────────────────────
echo "" | base64 -d | tar -xzf - -C "$LYAI_DIR/frontend"

echo ""; echo "▶  [5/7] Backend — entorno virtual + dependencias"; echo ""
cd "$LYAI_DIR/backend"
python3 -m venv .venv
.venv/bin/pip install -q -r requirements.txt

echo ""; echo "▶  [6/7] Frontend — build web estático"; echo ""
cd "$LYAI_DIR/frontend"
npm install --silent
EXPO_NO_DEPENDENCY_VALIDATION=1 EXPO_PUBLIC_API_URL=https://lyai.ch \
  npx expo export --platform web --output-dir dist 2>&1 | tail -5

echo ""; echo "▶  [7/7] nginx + servicio systemd"; echo ""

# nginx
cat > /etc/nginx/sites-available/lyai.ch << 'NGINX'
server {
    listen 80;
    server_name lyai.ch www.lyai.ch;
    return 301 https://$host$request_uri;
}

server {
    listen 443 ssl;
    server_name lyai.ch www.lyai.ch;

    ssl_certificate     /etc/letsencrypt/live/lyai.ch/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/lyai.ch/privkey.pem;
    ssl_protocols       TLSv1.2 TLSv1.3;
    ssl_ciphers         HIGH:!aNULL:!MD5;

    root /var/www/lyai/frontend/dist;
    index index.html;

    location /api/ {
        proxy_pass         http://127.0.0.1:8787;
        proxy_http_version 1.1;
        proxy_set_header   Host              $host;
        proxy_set_header   X-Real-IP         $remote_addr;
        proxy_set_header   X-Forwarded-Proto https;
        proxy_read_timeout 30s;
    }

    location / {
        try_files $uri $uri/ /index.html;
        add_header Cache-Control "no-cache";
    }

    location /_expo/ {
        expires 1y;
        add_header Cache-Control "public, immutable";
    }

    add_header Strict-Transport-Security "max-age=31536000" always;
    add_header X-Frame-Options "SAMEORIGIN";
    add_header X-Content-Type-Options "nosniff";
}
NGINX

ln -sf /etc/nginx/sites-available/lyai.ch /etc/nginx/sites-enabled/lyai.ch
rm -f /etc/nginx/sites-enabled/default

# Test SSL cert exists
if [ ! -f "$CERT_DIR/fullchain.pem" ]; then
  echo "⚠  Certificado no encontrado en $CERT_DIR"
  echo "   Ejecuta: certbot --nginx -d lyai.ch -d www.lyai.ch"
  # Serve HTTP only temporarily
  sed -i '/listen 443/,/^}/d; s/return 301.*//' /etc/nginx/sites-available/lyai.ch || true
fi

nginx -t && (systemctl reload nginx 2>/dev/null || nginx -s reload 2>/dev/null || nginx)

# systemd service para el backend
cat > /etc/systemd/system/lyai-backend.service << 'SVC'
[Unit]
Description=LyAi FastAPI backend
After=network.target

[Service]
User=root
WorkingDirectory=/var/www/lyai/backend
ExecStart=/var/www/lyai/backend/.venv/bin/uvicorn main:app --host 127.0.0.1 --port 8787 --workers 2
Restart=always
RestartSec=3
StandardOutput=journal
StandardError=journal

[Install]
WantedBy=multi-user.target
SVC

systemctl daemon-reload
systemctl enable lyai-backend
systemctl restart lyai-backend

sleep 2
if curl -s http://127.0.0.1:8787/api/health | grep -q "ok"; then
  echo ""; echo "✅  Backend OK"
else
  echo ""; echo "⚠  Backend no responde — revisa: journalctl -u lyai-backend -n 30"
fi


echo ""; echo "▶  [EXTRA] SSL — Let's Encrypt + Hetzner DNS"; echo ""
pip3 install certbot certbot-dns-hetzner -q 2>&1 | tail -2
mkdir -p /etc/letsencrypt
cat > /etc/letsencrypt/hetzner.ini << 'HCREDS'
dns_hetzner_api_token = Zr6NQwk9mo1OjBnxGIoHABvbKtE03yVbi1r5exPQFyfuUDEmjkeIDGzIWC7wJui1
HCREDS
chmod 600 /etc/letsencrypt/hetzner.ini
pip3 install cffi --ignore-installed --target /usr/local/lib/python3.$(python3 -c "import sys;print(sys.version_info.minor)")/dist-packages -q 2>&1 | tail -1
certbot certonly --authenticator dns-hetzner \
  --dns-hetzner-credentials /etc/letsencrypt/hetzner.ini \
  -d lyai.ch -d www.lyai.ch \
  --non-interactive --agree-tos -m lyai.pro@hotmail.com 2>&1

# Reload nginx with SSL
nginx -t && (systemctl reload nginx 2>/dev/null || nginx -s reload 2>/dev/null)

echo ""
echo "═══════════════════════════════════════"
echo "  ✅  LyAi instalado en $LYAI_DIR"
echo "  🌐  https://lyai.ch"
echo "  📡  API: https://lyai.ch/api/health"
echo "═══════════════════════════════════════"
echo ""
